import{_ as e,o as r,c as a,an as d}from"./chunks/framework.ubcH7j8_.js";const f=JSON.parse('{"title":"Service Map","description":"","frontmatter":{},"headers":[],"relativePath":"services/index.md","filePath":"services/index.md","lastUpdated":1773164166000}'),i={name:"services/index.md"};function o(s,t,n,c,l,h){return r(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="service-map" tabindex="-1">Service Map <a class="header-anchor" href="#service-map" aria-label="Permalink to &quot;Service Map&quot;">​</a></h1><p>The ARC Platform composes services into profiles — <strong>think</strong>, <strong>reason</strong>, and <strong>ultra-instinct</strong> — each building on the previous tier. Start with <code>think</code> for core infrastructure, add <code>reason</code> for AI capabilities, and <code>ultra-instinct</code> for the full platform (coming soon).</p><table tabindex="0"><thead><tr><th>Service</th><th>Codename</th><th>Port(s)</th><th>Description</th></tr></thead><tbody><tr><td><a href="./gateway.html">gateway</a></td><td>Heimdall</td><td>80, 8090</td><td>API gateway — routes all inbound HTTP traffic (Traefik)</td></tr><tr><td><a href="./messaging.html">messaging</a></td><td>Flash</td><td>4222, 8222</td><td>Ephemeral message broker for agent-to-agent communication (NATS)</td></tr><tr><td><a href="./streaming.html">streaming</a></td><td>Dr. Strange</td><td>6650, 8082</td><td>Durable event streaming with replay (Apache Pulsar)</td></tr><tr><td><a href="./cache.html">cache</a></td><td>Sonic</td><td>6379</td><td>Sub-millisecond key-value cache for sessions and rate limits (Redis)</td></tr><tr><td><a href="./sql-db.html">persistence</a></td><td>Oracle</td><td>5432</td><td>Relational long-term memory with vector search (PostgreSQL + pgvector)</td></tr><tr><td>cortex</td><td>Cortex</td><td>8801</td><td>Platform bootstrap service — workspace init and health orchestration</td></tr><tr><td><a href="./friday.html">friday-collector</a></td><td>Friday Collector</td><td>4317</td><td>OTEL collector — receives traces and metrics from all services</td></tr><tr><td><a href="./reasoner.html">reasoner</a></td><td>Sherlock</td><td>8802</td><td>LLM reasoning engine with RAG and streaming (LangGraph)</td></tr><tr><td><a href="./friday.html">otel</a></td><td>Friday</td><td>3301, 8080</td><td>Observability UI — traces, metrics, dashboards (SigNoz + ClickHouse)</td></tr><tr><td><a href="./realtime.html">realtime</a></td><td>Daredevil</td><td>7880–7882</td><td>WebRTC media routing for low-latency voice and video (LiveKit)</td></tr><tr><td><a href="./vault.html">vault</a></td><td>Nick Fury</td><td>8200</td><td>Secrets manager — dynamic secrets and encryption-as-a-service (OpenBao)</td></tr><tr><td><a href="./flags.html">flags</a></td><td>Mystique</td><td>4242</td><td>Feature flags with OpenFeature compatibility (Unleash)</td></tr><tr><td><a href="./storage.html">storage</a></td><td>Tardis</td><td>9000, 9001</td><td>S3-compatible object storage for artifacts and model weights (MinIO)</td></tr><tr><td><a href="./voice.html">voice</a></td><td>Scarlett</td><td>8803</td><td>Voice agent — STT, LLM, TTS pipeline with WebRTC support</td></tr></tbody></table><h2 id="profiles" tabindex="-1">Profiles <a class="header-anchor" href="#profiles" aria-label="Permalink to &quot;Profiles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Profile</th><th>Services</th><th>Use case</th></tr></thead><tbody><tr><td><code>think</code></td><td>gateway, messaging, streaming, cache, persistence, cortex, friday-collector</td><td>Core infrastructure — minimal footprint</td></tr><tr><td><code>reason</code></td><td>think + reasoner + voice + <em>growing</em></td><td>AI development — reasoning and voice, more services being added</td></tr><tr><td><code>ultra-instinct</code></td><td><em>Coming soon</em></td><td>Full platform with all capabilities</td></tr></tbody></table>',5)])])}const g=e(i,[["render",o]]);export{f as __pageData,g as default};
